'use client';

import { useSearchParams } from 'next/navigation';
import { EditorProvider } from '@/contexts/EditorContext';
import { PropertiesPanel } from '@/components/editor/PropertiesPanel';
import { Button } from '@/components/ui/button';
import { PanelLeft, PanelRight } from 'lucide-react';
import { useState } from 'react';

// Import your components
import Navigation from "@/components/Navigation";
import Hero from "@/components/Hero";
import HowItWorks from "@/components/HowItWorks";
import ServicesSection from "@/components/ServicesSection";
import Reviews from "@/components/Reviews";
import Contact from "@/components/Contact";
import Footer from "@/components/Footer";
import { DraggableWrapper } from '@/components/editor/DraggableWrapper';

export default function BuilderLanding() {
  const searchParams = useSearchParams();
  const isEditMode = searchParams.get('edit') === 'true';
  const [showProperties, setShowProperties] = useState(true);

  const toggleProperties = () => {
    setShowProperties(!showProperties);
  };

  const renderContent = () => (
    <>
      <DraggableWrapper id="navigation">
        <Navigation />
      </DraggableWrapper>
      <DraggableWrapper id="hero">
        <Hero />
      </DraggableWrapper>
      <DraggableWrapper id="how-it-works">
        <HowItWorks />
      </DraggableWrapper>
      <DraggableWrapper id="services">
        <ServicesSection />
      </DraggableWrapper>
      <DraggableWrapper id="reviews">
        <Reviews />
      </DraggableWrapper>
      <DraggableWrapper id="contact">
        <Contact />
      </DraggableWrapper>
      <DraggableWrapper id="footer">
        <Footer />
      </DraggableWrapper>
    </>
  );

  if (!isEditMode) {
    return <main>{renderContent()}</main>;
  }

  return (
    <EditorProvider isEditor>
      <div className="flex h-screen bg-gray-100">
        {/* Main Content */}
        <div className="flex-1 overflow-auto">
          <div className="relative h-full">
            <div className="absolute top-4 right-4 z-50">
              <Button 
                variant="outline" 
                size="icon" 
                onClick={toggleProperties}
                className="bg-white"
              >
                {showProperties ? <PanelLeft className="h-4 w-4" /> : <PanelRight className="h-4 w-4" />}
              </Button>
            </div>
            <div className="max-w-7xl mx-auto bg-white min-h-full">
              {renderContent()}
            </div>
          </div>
        </div>
        
        {/* Properties Panel */}
        {showProperties && <PropertiesPanel />}
      </div>
    </EditorProvider>
  );
}
