'use client'

import { Button } from "@/components/ui/button";
import { Menu, X, ChevronDown, HelpCircle, MessageSquare, LifeBuoy, BookOpen, User, Zap } from "lucide-react";
import { useEffect, useState } from "react";
import Link from "next/link";
import { useRouter, usePathname } from "next/navigation";
import * as DropdownMenu from "@radix-ui/react-dropdown-menu";

const Navigation = () => {
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
  const [isCustomerAuthenticated, setIsCustomerAuthenticated] = useState(false);
  const router = useRouter();
  const pathname = usePathname();

  useEffect(() => {
    if (typeof window === "undefined") return;

    const syncAuthState = () => {
      const isAuthed = window.localStorage.getItem("customerAuth") === "true";
      setIsCustomerAuthenticated(isAuthed);
    };

    const handleCustomAuthEvent = () => syncAuthState();

    syncAuthState();
    window.addEventListener("storage", syncAuthState);
    window.addEventListener("customer-auth-changed", handleCustomAuthEvent);

    return () => {
      window.removeEventListener("storage", syncAuthState);
      window.removeEventListener("customer-auth-changed", handleCustomAuthEvent);
    };
  }, []);

  const handleSectionClick = (sectionId: string) => {
    if (pathname !== '/') {
      // If not on home page, navigate to home first, then scroll
      router.push('/');
      setTimeout(() => {
        const element = document.getElementById(sectionId);
        if (element) {
          element.scrollIntoView({ behavior: 'smooth' });
        }
      }, 100);
    } else {
      // If on home page, just scroll
      const element = document.getElementById(sectionId);
      if (element) {
        element.scrollIntoView({ behavior: 'smooth' });
      }
    }
    setMobileMenuOpen(false);
  };

  return (
    <nav className="fixed top-0 left-0 right-0 z-50 bg-background/95 backdrop-blur-md border-b border-primary/20 shadow-lg">
      <div className="container mx-auto px-4">
        <div className="flex items-center justify-between h-16">
          <Link href="/" className="flex items-center gap-3 cursor-pointer">
            <img src="/images/logo.png" alt="Premier Pro Cleaners" className="h-12 w-12" />
            <span className="text-xl font-bold gradient-text">Premier Pro Cleaners</span>
          </Link>
          
          {/* Desktop Navigation */}
          <div className="hidden md:flex items-center space-x-8">
            <button 
              onClick={() => handleSectionClick('how-it-works')} 
              className="text-foreground hover:text-primary transition-colors cursor-pointer"
            >
              How It Works
            </button>
            <button 
              onClick={() => handleSectionClick('services')} 
              className="text-foreground hover:text-primary transition-colors cursor-pointer"
            >
              Services
            </button>
            <button 
              onClick={() => handleSectionClick('reviews')} 
              className="text-foreground hover:text-primary transition-colors cursor-pointer"
            >
              Reviews
            </button>
            <button 
              onClick={() => handleSectionClick('contact')} 
              className="text-foreground hover:text-primary transition-colors cursor-pointer"
            >
              Contact
            </button>
            <DropdownMenu.Root>
              <DropdownMenu.Trigger asChild>
                <button className="flex items-center text-foreground hover:text-primary transition-colors cursor-pointer">
                  Support
                  <ChevronDown className="ml-1 h-4 w-4" />
                </button>
              </DropdownMenu.Trigger>
              <DropdownMenu.Portal>
                <DropdownMenu.Content className="min-w-[220px] bg-white rounded-md p-2 shadow-lg border border-gray-200 z-50" sideOffset={5}>
                  <DropdownMenu.Item className="group text-sm rounded-sm flex items-center px-2 py-2 outline-none cursor-pointer hover:bg-gray-50 hover:text-primary">
                    <HelpCircle className="mr-2 h-4 w-4" />
                    <span>Help Center</span>
                  </DropdownMenu.Item>
                  <DropdownMenu.Item className="group text-sm rounded-sm flex items-center px-2 py-2 outline-none cursor-pointer hover:bg-gray-50 hover:text-primary">
                    <MessageSquare className="mr-2 h-4 w-4" />
                    <span>FAQs</span>
                  </DropdownMenu.Item>
                  <DropdownMenu.Item className="group text-sm rounded-sm flex items-center px-2 py-2 outline-none cursor-pointer hover:bg-gray-50 hover:text-primary">
                    <LifeBuoy className="mr-2 h-4 w-4" />
                    <span>Contact Support</span>
                  </DropdownMenu.Item>
                  <DropdownMenu.Item className="group text-sm rounded-sm flex items-center px-2 py-2 outline-none cursor-pointer hover:bg-gray-50 hover:text-primary">
                    <BookOpen className="mr-2 h-4 w-4" />
                    <span>Tutorials</span>
                  </DropdownMenu.Item>
                  <DropdownMenu.Item className="group text-sm rounded-sm flex items-center px-2 py-2 outline-none cursor-pointer hover:bg-gray-50 hover:text-primary">
                    <User className="mr-2 h-4 w-4" />
                    <span>Account Support</span>
                  </DropdownMenu.Item>
                  <DropdownMenu.Item className="group text-sm rounded-sm flex items-center px-2 py-2 outline-none cursor-pointer hover:bg-gray-50 hover:text-primary">
                    <Zap className="mr-2 h-4 w-4" />
                    <span>Request a Feature</span>
                  </DropdownMenu.Item>
                  <DropdownMenu.Arrow className="fill-white" />
                </DropdownMenu.Content>
              </DropdownMenu.Portal>
            </DropdownMenu.Root>
            <Button variant="outline" size="sm" asChild>
              <Link href={isCustomerAuthenticated ? "/customer/dashboard" : "/login"}>
                {isCustomerAuthenticated ? "My Dashboard" : "Login"}
              </Link>
            </Button>
            <Button asChild size="sm">
              <Link href="/book-now">Book Now</Link>
            </Button>
          </div>

          {/* Mobile Menu Button */}
          <button
            className="md:hidden text-foreground"
            onClick={() => setMobileMenuOpen(!mobileMenuOpen)}
          >
            {mobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
          </button>
        </div>

        {/* Mobile Navigation */}
        {mobileMenuOpen && (
          <div className="md:hidden py-4 space-y-4">
            <button
              onClick={() => handleSectionClick('how-it-works')}
              className="block text-foreground hover:text-primary transition-colors w-full text-left"
            >
              How It Works
            </button>
            <button
              onClick={() => handleSectionClick('services')}
              className="block text-foreground hover:text-primary transition-colors w-full text-left"
            >
              Services
            </button>
            <button
              onClick={() => handleSectionClick('reviews')}
              className="block text-foreground hover:text-primary transition-colors w-full text-left"
            >
              Reviews
            </button>
            <button
              onClick={() => handleSectionClick('contact')}
              className="block text-foreground hover:text-primary transition-colors w-full text-left"
            >
              Contact
            </button>
            <div className="flex flex-col space-y-2 pt-2">
              <Button variant="outline" size="sm" asChild>
                <Link href={isCustomerAuthenticated ? "/customer/dashboard" : "/login"}>
                  {isCustomerAuthenticated ? "My Dashboard" : "Login"}
                </Link>
              </Button>
              <Button size="sm" asChild>
                <Link href="/book-now">Get Started</Link>
              </Button>
            </div>
          </div>
        )}
      </div>
    </nav>
  );
};

export default Navigation;
