'use client';

import { useEditor } from '@/contexts/EditorContext';
import { Button } from '../ui/button';
import { Input } from '../ui/input';
import { Label } from '../ui/label';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '../ui/tabs';

export function PropertiesPanel() {
  const { selectedComponent } = useEditor();

  if (!selectedComponent) {
    return (
      <div className="w-64 p-4 bg-white border-l h-full">
        <p className="text-sm text-muted-foreground text-center mt-8">
          Select a component to edit its properties
        </p>
      </div>
    );
  }

  return (
    <div className="w-64 p-4 bg-white border-l h-full overflow-y-auto">
      <Tabs defaultValue="content" className="w-full">
        <TabsList className="grid w-full grid-cols-2">
          <TabsTrigger value="content">Content</TabsTrigger>
          <TabsTrigger value="style">Style</TabsTrigger>
        </TabsList>
        
        <TabsContent value="content" className="mt-4 space-y-4">
          <div className="space-y-2">
            <Label htmlFor="title">Title</Label>
            <Input id="title" defaultValue="Premier Pro Cleaners" />
          </div>
          <div className="space-y-2">
            <Label htmlFor="description">Description</Label>
            <Input id="description" defaultValue="Professional Cleaning Services" />
          </div>
        </TabsContent>
        
        <TabsContent value="style" className="mt-4 space-y-4">
          <div className="space-y-2">
            <Label htmlFor="background">Background Color</Label>
            <Input type="color" id="background" defaultValue="#ffffff" className="h-10 w-full p-1" />
          </div>
          <div className="space-y-2">
            <Label htmlFor="textColor">Text Color</Label>
            <Input type="color" id="textColor" defaultValue="#000000" className="h-10 w-full p-1" />
          </div>
        </TabsContent>
      </Tabs>
      
      <div className="mt-6 pt-4 border-t">
        <Button variant="outline" className="w-full">
          Save Changes
        </Button>
      </div>
    </div>
  );
}
