'use client';

import { useEditor } from '@/contexts/EditorContext';
import { cn } from '@/lib/utils';
import { GripVertical, Trash2 } from 'lucide-react';
import { Button } from '../ui/button';

type DraggableWrapperProps = {
  id: string;
  children: React.ReactNode;
  className?: string;
  onDelete?: () => void;
};

export function DraggableWrapper({ id, children, className, onDelete }: DraggableWrapperProps) {
  const { isEditor, selectedComponent, setSelectedComponent } = useEditor();
  const isSelected = selectedComponent === id;

  if (!isEditor) {
    return <>{children}</>;
  }

  return (
    <div 
      className={cn(
        'relative group',
        isSelected && 'ring-2 ring-blue-500 rounded-md',
        className
      )}
      onClick={(e) => {
        e.stopPropagation();
        setSelectedComponent(id);
      }}
    >
      {isEditor && (
        <div className="absolute -left-8 top-0 h-full flex flex-col items-center space-y-1 opacity-0 group-hover:opacity-100 transition-opacity">
          <Button
            variant="ghost"
            size="icon"
            className="w-6 h-6 rounded-full p-1 hover:bg-gray-200"
            onMouseDown={(e) => {
              e.stopPropagation();
              // Handle drag start
            }}
          >
            <GripVertical className="w-3 h-3" />
          </Button>
          {onDelete && (
            <Button
              variant="ghost"
              size="icon"
              className="w-6 h-6 rounded-full p-1 hover:bg-red-100 hover:text-red-600"
              onClick={(e) => {
                e.stopPropagation();
                onDelete();
              }}
            >
              <Trash2 className="w-3 h-3" />
            </Button>
          )}
        </div>
      )}
      {children}
    </div>
  );
}
